-- Seed ~100 recipes for a given user.
-- Usage:
--   psql -d cookmaid -v user_id="'<your-uuid>'" -f sandbox/claude/seed_recipes.sql

-- Stagger created_at so cursor pagination has distinct values

-- Add a few free-text ingredients to each recipe for realism
SELECT r.id, 'Salt', NULL FROM recipes r WHERE r.user_id = :user_id;

SELECT r.id, 'Olive oil', 2 FROM recipes r WHERE r.user_id = :user_id;

SELECT r.id, 'Black pepper', NULL FROM recipes r WHERE r.user_id = :user_id;
